edits.new:
data {
  int<lower=0> N;              // number of observations (groups)
  int<lower=0> n[N];          // number of trials
  int<lower=0> y[N];          // number of successes
}

parameters {
  real<lower=0> alpha;        // Beta shape parameter alpha
  real<lower=0> beta;         // Beta shape parameter beta
  vector<lower=0, upper=1>[N] theta;  // group-level probabilities
}

model {
  // Prior: p(alpha, beta) proportional to (alpha + beta)^(-5/2)
  target += -2.5 * log(alpha + beta);

  // Hierarchical prior on theta
  theta ~ beta(alpha, beta);

  // Likelihood
  y ~ binomial(n, theta);
}

