cat > /tmp/reparam.stan <<'EOF'
data {
  int<lower=0> N;
  int<lower=0> n[N];
  int<lower=0> y[N];
}
parameters {
  real mu;            // logit of mean phi = alpha/(alpha+beta)
  real log_lambda;    // log(alpha+beta)
  vector<lower=0, upper=1>[N] theta;
}
transformed parameters {
  real<lower=0> lambda = exp(log_lambda);
  real<lower=0,upper=1> phi = inv_logit(mu);
  real<lower=0> alpha = lambda * phi;
  real<lower=0> beta  = lambda * (1 - phi);
}
model {
  // prior (alpha+beta)^(-5/2) + Jacobian to (mu, log_lambda)
  target += -0.5 * log_lambda + log(phi) + log1m(phi);
  theta ~ beta(alpha, beta);
  y ~ binomial(n, theta);
}
EOF
cat > /tmp/reparam.R <<'EOF'
library(rstan)
options(mc.cores=4)
d <- read.csv("/app/data.csv")
sd <- list(N=nrow(d), n=as.integer(d$n), y=as.integer(d$y))
fit <- stan("/tmp/reparam.stan", data=sd, chains=4, iter=40000, seed=1,
            control=list(adapt_delta=0.95))
p <- rstan::extract(fit)
cat("REPARAM alpha:", mean(p$alpha), " beta:", mean(p$beta), "\n")
cat("divergences check done\n")
EOF
cd /tmp && Rscript reparam.R > /tmp/reparam.log 2>&1

